# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        handleShareIntent(intent)
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                if ("text/plain" == intent.type) {
                    val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                    processSharedText(sharedText)
                } else if ("image/*" == intent.type) {
                    val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                    processSharedImage(imageUri)
                }
            }
        }
    }

    private fun processSharedText(text: String?) {
        text?.let {
            // Process the shared text
            Toast.makeText(this, "Received Text: $it", Toast.LENGTH_LONG).show()
        } ?: run {
            Toast.makeText(this, "No text received", Toast.LENGTH_SHORT).show()
        }
    }

    private fun processSharedImage(uri: Uri?) {
        uri?.let {
            // Process the shared image
            Toast.makeText(this, "Received Image: $it", Toast.LENGTH_LONG).show()
        } ?: run {
            Toast.makeText(this, "No image received", Toast.LENGTH_SHORT).show()
        }
    }
}